1	<!DOCTYPE html>
2	<html lang="en">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
6	<title>Brian Harris BMW — PMA Intelligence</title>
7	<style>
8	  :root {
9	    --bmw-blue: #1C69D4;
10	    --bg-dark: #0d1117;
11	    --card-bg: #161b22;
12	    --card-border: #30363d;
13	    --text-primary: #e6edf3;
14	    --text-secondary: #8b949e;
15	    --green: #3fb950;
16	    --yellow: #d29922;
17	    --red: #f85149;
18	    --orange: #db6d28;
19	  }
20	
21	  * { margin: 0; padding: 0; box-sizing: border-box; }
22	
23	  body {
24	    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, sans-serif;
25	    background: var(--bg-dark);
26	    color: var(--text-primary);
27	    line-height: 1.6;
28	    min-height: 100vh;
29	  }
30	
31	  header {
32	    background: linear-gradient(135deg, #0a0e14 0%, #111820 100%);
33	    border-bottom: 2px solid var(--bmw-blue);
34	    padding: 2rem 2rem 1.5rem;
35	    text-align: center;
36	  }
37	
38	  header h1 {
39	    font-size: 1.75rem;
40	    font-weight: 700;
41	    letter-spacing: 0.5px;
42	  }
43	
44	  header h1 span { color: var(--bmw-blue); }
45	
46	  header .subtitle {
47	    color: var(--text-secondary);
48	    font-size: 0.9rem;
49	    margin-top: 0.35rem;
50	  }
51	
52	  .badge {
53	    display: inline-block;
54	    font-size: 0.7rem;
55	    font-weight: 600;
56	    text-transform: uppercase;
57	    letter-spacing: 1px;
58	    padding: 0.2rem 0.6rem;
59	    border-radius: 3px;
60	    margin-top: 0.5rem;
61	  }
62	
63	  .badge-live { background: var(--bmw-blue); color: #fff; }
64	
65	  main { max-width: 1280px; margin: 0 auto; padding: 2rem 1.5rem; }
66	
67	  .section-label {
68	    font-size: 0.75rem;
69	    font-weight: 600;
70	    text-transform: uppercase;
71	    letter-spacing: 1.5px;
72	    color: var(--text-secondary);
73	    margin-bottom: 1rem;
74	  }
75	
76	  /* ---- Competitor Cards ---- */
77	  .cards { display: grid; grid-template-columns: repeat(3, 1fr); gap: 1.25rem; margin-bottom: 2.5rem; }
78	
79	  .card {
80	    background: var(--card-bg);
81	    border: 1px solid var(--card-border);
82	    border-radius: 10px;
83	    padding: 1.5rem;
84	    position: relative;
85	    transition: border-color 0.2s;
86	  }
87	
88	  .card:hover { border-color: var(--bmw-blue); }
89	
90	  .card.primary { border-top: 3px solid var(--bmw-blue); }
91	  .card.competitor { border-top: 3px solid var(--card-border); }
92	
93	  .card-header { display: flex; align-items: center; gap: 0.75rem; margin-bottom: 1.25rem; }
94	
95	  .logo-placeholder {
96	    width: 44px; height: 44px;
97	    border-radius: 8px;
98	    display: flex; align-items: center; justify-content: center;
99	    font-weight: 700; font-size: 0.8rem; color: #fff; flex-shrink: 0;
100	  }

